"use client";

import { useEffect, useState, useRef } from "react";
import Script from "next/script"; // Next.js 스크립트 로더
import { getPharmacyList } from "@/util/nightApi";
import "./pharmacy.css";

declare global {
  interface Window {
    kakao: any;
  }
}

interface Pharmacy {
  name: string;
  address: string;
  tel: string;
  lat: number;
  lon: number;
  endTime: string;
}

export default function PharmacyPage() {
  // ⚠️ 여기에 카카오 JavaScript 키를 넣으세요!
  const KAKAO_API_KEY = "발급받은_JavaScript_키를_넣으세요"; 

  const [loading, setLoading] = useState(false);
  const [pharmacies, setPharmacies] = useState<Pharmacy[]>([]);
  const [errorMsg, setErrorMsg] = useState("");
  
  // 지도 관련 상태
  const mapRef = useRef<HTMLElement>(null); // 지도 DOM 참조
  const [map, setMap] = useState<any>(null); // 카카오맵 객체
  const [markers, setMarkers] = useState<any[]>([]); // 마커 배열

  // 초기 로딩 (현재 위치)
  useEffect(() => {
    // 카카오맵 스크립트가 로드된 후 실행되도록 Script 컴포넌트의 onReady 사용
    if (window.kakao && window.kakao.maps) {
      initMapAtCurrentLocation();
    } else {
      getMyLocation(); // 스크립트 로드 전이라면 일단 브라우저 위치만 획득
    }
  }, []);

  // 1. 현재 위치 가져오기 (초기 진입용)
  const getMyLocation = () => {
    if (!navigator.geolocation) {
      setErrorMsg("위치 기능을 사용할 수 없습니다.");
      return;
    }

    setLoading(true);
    navigator.geolocation.getCurrentPosition(
      (position) => {
        const { latitude, longitude } = position.coords;
        // 지도 초기화 또는 이동
        if (!map) {
          // 지도가 아직 없으면 생성 (스크립트 로드 대기 등)
        } else {
          // 지도가 있으면 거기로 이동
          moveMapTo(latitude, longitude);
          fetchPharmacies(latitude, longitude);
        }
      },
      (err) => {
        setErrorMsg("위치 권한을 허용해주세요. (기본 위치: 서울시청)");
        // 권한 거부 시 기본 위치(서울시청)로 지도 로드
        const defaultLat = 37.566826;
        const defaultLon = 126.9786567;
        if(map) {
          moveMapTo(defaultLat, defaultLon);
          fetchPharmacies(defaultLat, defaultLon);
        }
        setLoading(false);
      }
    );
  };

  // 2. 카카오맵 초기화 (스크립트 로드 완료 시 호출)
  const initMapAtCurrentLocation = () => {
    if (!navigator.geolocation) return;
    
    navigator.geolocation.getCurrentPosition((position) => {
        const { latitude, longitude } = position.coords;
        loadKakaoMap(latitude, longitude);
        fetchPharmacies(latitude, longitude);
    }, () => {
        // 위치 권한 거부 시 서울시청 기준
        const lat = 37.566826;
        const lon = 126.9786567;
        loadKakaoMap(lat, lon);
        fetchPharmacies(lat, lon);
    });
  };

  const loadKakaoMap = (lat: number, lon: number) => {
    const container = document.getElementById("map");
    const options = {
      center: new window.kakao.maps.LatLng(lat, lon),
      level: 4, // 확대 레벨
    };
    const newMap = new window.kakao.maps.Map(container, options);
    setMap(newMap);
  };

  // 3. 지도 중심 이동 함수
  const moveMapTo = (lat: number, lon: number) => {
    if (map) {
      const moveLatLon = new window.kakao.maps.LatLng(lat, lon);
      map.setCenter(moveLatLon);
    }
  };

  // 4. "이 위치에서 재검색" 버튼 클릭 시
  const handleSearchCurrentMap = () => {
    if (!map) return;
    
    // 현재 지도 중심 좌표 가져오기
    const center = map.getCenter(); 
    const lat = center.getLat();
    const lon = center.getLng();

    fetchPharmacies(lat, lon);
  };

  // 5. 백엔드 API 호출 & 마커 찍기
  const fetchPharmacies = async (lat: number, lon: number) => {
    setLoading(true);
    try {
      const data = await getPharmacyList(lat, lon);
      setPharmacies(data);
      if (data.length === 0) setErrorMsg("");
      
      // 지도에 마커 표시
      if (map) {
        updateMarkers(map, data);
      }

    } catch (e) {
      setErrorMsg("약국 정보를 불러오는데 실패했습니다.");
    } finally {
      setLoading(false);
    }
  };

  // 마커 업데이트 (기존 마커 지우고 새로 찍기)
  const updateMarkers = (currentMap: any, data: Pharmacy[]) => {
    // 기존 마커 제거
    markers.forEach(marker => marker.setMap(null));
    
    const newMarkers = data.map(ph => {
      const markerPosition = new window.kakao.maps.LatLng(ph.lat, ph.lon);
      const marker = new window.kakao.maps.Marker({
        position: markerPosition
      });
      
      // 마커 클릭 시 인포윈도우 (약국 이름) 표시
      const iwContent = `<div style="padding:5px;font-size:13px;color:#000;">${ph.name}<br>${ph.endTime} 마감</div>`;
      const infowindow = new window.kakao.maps.InfoWindow({
        content: iwContent
      });

      window.kakao.maps.event.addListener(marker, 'mouseover', function() {
        infowindow.open(currentMap, marker);
      });
      window.kakao.maps.event.addListener(marker, 'mouseout', function() {
        infowindow.close();
      });

      marker.setMap(currentMap);
      return marker;
    });

    setMarkers(newMarkers);
  };
  
  // 지도가 생성된 후에 데이터가 바뀐 경우 마커 업데이트 (useEffect)
  useEffect(() => {
    if (map && pharmacies.length > 0) {
      updateMarkers(map, pharmacies);
    }
  }, [map]); // map이 나중에 로드될 수도 있으므로 의존성 추가

  return (
    <>
      {/* 카카오맵 스크립트 로드 */}
      <Script 
        src={`//dapi.kakao.com/v2/maps/sdk.js?appkey=${KAKAO_API_KEY}&autoload=false`}
        strategy="afterInteractive"
        onReady={() => {
          window.kakao.maps.load(() => {
            initMapAtCurrentLocation();
          });
        }}
      />

      <div className="pharmacy-container">
        <div className="pharmacy-header">
          <h1 className="pharmacy-title">심야 약국 지도 🗺️</h1>
          <p className="pharmacy-desc">
            지도를 움직여 <strong>저녁 7시 이후</strong> 운영하는 약국을 찾아보세요.
          </p>
        </div>

        {/* 지도 영역 */}
        <div className="map-wrapper">
          <div id="map"></div>
          {/* 지도 위에 떠있는 재검색 버튼 */}
          <button className="btn-research" onClick={handleSearchCurrentMap} disabled={loading}>
            {loading ? "검색 중..." : "📍 현 지도에서 재검색"}
          </button>
        </div>

        {/* 상태 메시지 */}
        <div style={{marginBottom: '20px', color: '#666', fontSize:'14px'}}>
            {errorMsg ? <span style={{color:'red'}}>{errorMsg}</span> : `총 ${pharmacies.length}개의 야간 약국을 찾았습니다.`}
        </div>

        {/* 리스트 영역 */}
        <div className="pharmacy-list">
          {pharmacies.length > 0 ? (
            pharmacies.map((ph, index) => (
              <div key={index} className="pharmacy-card">
                <div className="ph-info">
                  <span className="ph-name">{ph.name}</span>
                  <div className="ph-addr">{ph.address}</div>
                  <div style={{display:'flex', gap:'10px', alignItems:'center', marginTop:'8px'}}>
                    <span className="ph-time-badge">
                      마감: {ph.endTime}
                    </span>
                    <a href={`tel:${ph.tel}`} style={{textDecoration:'none', color:'#666', fontSize:'13px'}}>
                      📞 {ph.tel}
                    </a>
                  </div>
                </div>
                <div className="ph-distance">
                  <a 
                    href={`https://map.kakao.com/link/to/${ph.name},${ph.lat},${ph.lon}`} 
                    target="_blank" 
                    rel="noopener noreferrer"
                    style={{
                      backgroundColor: '#10b981', 
                      color: 'white', 
                      padding: '8px 12px', 
                      borderRadius: '6px', 
                      textDecoration: 'none',
                      fontSize: '13px'
                    }}
                  >
                    길찾기
                  </a>
                </div>
              </div>
            ))
          ) : (
            !loading && (
              <div className="empty-msg">
                지도 화면 내에 19시 이후 운영하는 약국이 없습니다.<br />
                지도를 다른 곳으로 이동하고 <strong>[현 지도에서 재검색]</strong>을 눌러보세요!
              </div>
            )
          )}
        </div>
      </div>
    </>
  );
}